const { chromium } = require('playwright');

(async () => {
  const browser = await chromium.connectOverCDP('http://127.0.0.1:9222');
  const context = browser.contexts()[0];
  const pages = context.pages();
  const page = pages.find(p => p.url().includes('xiaoman')) || pages[0];

  console.log('当前页面URL:', page.url());
  console.log('页面标题:', await page.title());

  // Take screenshot
  await page.screenshot({ path: 'okki_screenshot.png', fullPage: false });
  console.log('截图已保存');

  // Get key text content
  const text = await page.evaluate(() => document.body.innerText.substring(0, 5000));
  console.log('页面内容:\n', text);

  // Don't close browser - just disconnect
  await browser.disconnect();
  console.log('已断开连接，主浏览器仍运行中');
})().catch(err => {
  console.error('Error:', err);
  process.exit(1);
});

