const fs = require('fs');
const { Document, Packer, Paragraph, TextRun, HeadingLevel, Table, TableRow, TableCell, WidthType, BorderStyle, ShadingType, PageBreak } = require('docx');

// Load data from JSON
const data = JSON.parse(fs.readFileSync(__dirname + '/p0_analysis_data.json', 'utf8'));

// Helpers
function headerCell(text, width) {
  return new TableCell({
    width: { size: width, type: WidthType.PERCENTAGE },
    shading: { type: ShadingType.SOLID, color: '1a5276' },
    children: [new Paragraph({ children: [new TextRun({ text, bold: true, color: 'FFFFFF', size: 20, font: 'Microsoft YaHei' })], spacing: { before: 40, after: 40 } })],
  });
}

function cell(text, width) {
  return new TableCell({
    width: { size: width, type: WidthType.PERCENTAGE },
    children: [new Paragraph({ children: [new TextRun({ text, size: 19, font: 'Microsoft YaHei' })], spacing: { before: 30, after: 30 } })],
  });
}

function heading(text, level) {
  const sizes = {1: 32, 2: 28, 3: 24};
  return new Paragraph({ heading: level, children: [new TextRun({ text, bold: true, font: 'Microsoft YaHei', size: sizes[level] || 24 })], spacing: { before: 200, after: 100 } });
}

function para(text, opts = {}) {
  return new Paragraph({
    children: [new TextRun({ text, size: 21, font: 'Microsoft YaHei', ...opts })],
    spacing: { before: 60, after: 60 }
  });
}

function boldPara(label, text) {
  return new Paragraph({
    children: [
      new TextRun({ text: label, bold: true, size: 21, font: 'Microsoft YaHei' }),
      new TextRun({ text, size: 21, font: 'Microsoft YaHei' })
    ],
    spacing: { before: 40, after: 40 }
  });
}

// Build document
const children = [];

// Title
children.push(
  new Paragraph({ heading: HeadingLevel.HEADING_1, children: [new TextRun({ text: '外贸跟进方案 — P0客户完整分析', bold: true, font: 'Microsoft YaHei', size: 36 })], spacing: { after: 100 } }),
  para('生成日期：2026年4月30日'),
  para('数据来源：Okki平台 deep_scrape (2026-04-30T07-40 + 06-12 + cleaned_merged_v2)'),
  para('分析客户：14个P0客户（S级12个，A级2个） | 分析框架：四层渐进判断（SP v4.3）'),
  para(''),
  para('⚠️ 数据交叉验证说明：部分客户仅出现在单一抓取文件中（标注"未经交叉验证"）。31个P0在最新抓取中返回"DOM中未找到"，数据可能有缺失。Karl brown、Abdou Salam Kane、Dania Sanchez、Sarah nell roly、yoselyn Rodriguez 出现在两个以上文件中，数据一致。'),
  para('')
);

// Priority summary
children.push(heading('执行优先级概览', 1));
const pLevels = [
  { title: '🔴 第一梯队：今天必须处理（2人）', data: data.summary.urgent },
  { title: '🟡 第二梯队：48h内处理（3人）', data: data.summary.high },
  { title: '🟢 第三梯队：本周内处理（4人）', data: data.summary.medium },
  { title: '⚪ 第四梯队：按需轻触达（5人）', data: data.summary.low }
];

for (const level of pLevels) {
  children.push(heading(level.title, 2));
  const rows = [new TableRow({ children: [headerCell('客户', 20), headerCell('执行动作', 65), headerCell('时限', 15)] })];
  for (const item of level.data) {
    rows.push(new TableRow({ children: [cell(item.name, 20), cell(item.action, 65), cell(item.urgency, 15)] }));
  }
  children.push(new Table({ rows, width: { size: 100, type: WidthType.PERCENTAGE } }));
  children.push(para(''));
}

children.push(new Paragraph({ children: [new PageBreak()] }));
children.push(heading('逐客深度分析', 1));

// Each customer
for (let i = 0; i < data.customers.length; i++) {
  const c = data.customers[i];
  children.push(heading(`${i + 1}. ${c.name}  |  ${c.tier}级  |  ${c.country}  |  ${c.priority}`, 2));

  const infoRows = [
    new TableRow({ children: [headerCell('字段', 15), headerCell('内容', 85)] }),
    new TableRow({ children: [cell('阶段诊断', 15), cell(c.stage, 85)] }),
    new TableRow({ children: [cell('消息数量', 15), cell(c.messages + '条', 85)] }),
    new TableRow({ children: [cell('沟通语言', 15), cell(c.lang, 85)] }),
    new TableRow({ children: [cell('钩子方案', 15), cell(c.hook || '不使用钩子（直接回答/推下一步）', 85)] }),
  ];
  children.push(new Table({ rows: infoRows, width: { size: 100, type: WidthType.PERCENTAGE } }));
  children.push(para(''));

  children.push(heading('客户概况', 3));
  children.push(para(c.summary));

  children.push(heading('阶段分析', 3));
  children.push(para(c.stageDetail));

  if (c.blockage) {
    children.push(heading('卡点诊断', 3));
    children.push(para(c.blockage));
  }

  children.push(heading('下一步策略', 3));
  children.push(para(c.nextStep));

  children.push(heading('跟进话术', 3));
  children.push(boldPara('发送语言：', c.script.translateTo));
  children.push(new Paragraph({
    children: [new TextRun({ text: c.script.text, size: 21, font: 'Microsoft YaHei', italics: true })],
    spacing: { before: 80, after: 80 },
    border: {
      top: { style: BorderStyle.SINGLE, size: 1, color: '2980b9' },
      bottom: { style: BorderStyle.SINGLE, size: 1, color: '2980b9' },
      left: { style: BorderStyle.SINGLE, size: 1, color: '2980b9' },
      right: { style: BorderStyle.SINGLE, size: 1, color: '2980b9' }
    },
  }));

  if (c.postNote) {
    children.push(heading('内部备注', 3));
    children.push(para(c.postNote, { color: 'c0392b' }));
  }

  children.push(new Paragraph({ children: [new PageBreak()] }));
}

// Appendix
children.push(heading('附录：数据来源说明', 1));
children.push(para('1. deep_scrape_2026-04-30T07-40-03.json — 最新抓取，40个目标中6个成功，31个被跳过（DOM中未找到）'));
children.push(para('2. deep_scrape_2026-04-30T06-12-00.json — 第二次抓取，39个目标中6个成功，33个被跳过'));
children.push(para('3. deep_scrape_merged_v2_2026-04-29T13-23-38_cleaned.json — 清洗合并版，29个客户含完整消息'));
children.push(para('4. 交叉验证通过：Karl brown、Abdou Salam Kane、Dania Sanchez、Sarah nell roly、yoselyn Rodriguez 出现在两个以上文件中，数据一致'));
children.push(para('5. 其余9个客户仅在清洗合并文件中出现，标注"未经交叉验证"'));
children.push(para(''));

children.push(heading('附录：钩子素材状态速查', 1));
const hookRows = [
  new TableRow({ children: [headerCell('钩子ID', 25), headerCell('状态', 10), headerCell('本次使用情况', 65)] }),
  new TableRow({ children: [cell('hook_pampers_olympic', 25), cell('✅', 10), cell('Karl brown话术中嵌入（帮宝适奥运背书）', 65)] }),
  new TableRow({ children: [cell('hook_iso_cert', 25), cell('✅', 10), cell('Lisa Ketelsen话术中提（德国客户重认证）', 65)] }),
  new TableRow({ children: [cell('hook_fabric_library', 25), cell('⚠️', 10), cell('martin wamundila使用替代方案（发面料图而非完整可视化库）', 65)] }),
  new TableRow({ children: [cell('hook_disney_ip', 25), cell('✅', 10), cell('本次未使用', 65)] }),
  new TableRow({ children: [cell('hook_fabric_compare', 25), cell('⚠️', 10), cell('本次未使用（静态对比图可用，视频M06待拍摄）', 65)] }),
  new TableRow({ children: [cell('hook_sample_fabric', 25), cell('❌ 禁用', 10), cell('待制备（M10），本次未使用', 65)] }),
  new TableRow({ children: [cell('hook_packing_shipping', 25), cell('❌ 禁用', 10), cell('待拍摄（M07），本次未使用', 65)] }),
  new TableRow({ children: [cell('hook_production_line', 25), cell('⚠️', 10), cell('本次未使用（已有基础素材但非专业拍摄）', 65)] }),
];
children.push(new Table({ rows: hookRows, width: { size: 100, type: WidthType.PERCENTAGE } }));

// Generate
const doc = new Document({ sections: [{ properties: {}, children }] });
Packer.toBuffer(doc).then(buffer => {
  const outPath = 'C:\\Users\\Administrator\\Desktop\\外贸跟进方案_P0完整分析_2026-04-30.docx';
  fs.writeFileSync(outPath, buffer);
  console.log('OK: ' + outPath);
});

