const { chromium } = require('playwright');
const fs = require('fs');
const path = require('path');

const DATA_DIR = path.join(__dirname, '..', 'data');
const USER_DATA = path.join(__dirname, '..', '.playwright_profile');

(async () => {
  // Launch with PERSISTENT context - this saves cookies between runs
  // If user logged in previously, session will be restored automatically
  const context = await chromium.launchPersistentContext(USER_DATA, {
    headless: false,
    args: ['--remote-debugging-port=9223'],
    viewport: { width: 1440, height: 900 }
  });

  const page = context.pages()[0] || await context.newPage();

  // Intercept API responses to capture customer data
  const apiData = [];
  page.on('response', async (response) => {
    const url = response.url();
    // OKKI CRM API endpoints that contain customer data
    if (url.includes('xiaoman.cn') || url.includes('onetalk') || url.includes('alibaba')) {
      try {
        const ct = response.headers()['content-type'] || '';
        if (ct.includes('json')) {
          const body = await response.json();
          apiData.push({
            url: url.substring(0, 200),
            status: response.status(),
            bodySize: JSON.stringify(body).length,
            data: body
          });
        }
      } catch (e) {}
    }
  });

  console.log('=== 启动浏览器，检查 OKKI 登录状态 ===');

  // Step 1: Try to access OKKI CRM directly
  await page.goto('https://crm.xiaoman.cn', { waitUntil: 'networkidle', timeout: 30000 });

  // Wait for page to stabilize
  await page.waitForTimeout(3000);

  const currentUrl = page.url();
  console.log('当前URL:', currentUrl);

  // Step 2: Check if we're on login page or already logged in
  if (currentUrl.includes('login.xiaoman.cn') || currentUrl.includes('login.alibaba')) {
    console.log('\n🔐 需要登录 OKKI');
    console.log('⚠️  请在浏览器中手动输入子账号密码登录');
    console.log('⚠️  登录前请确认同事不在阿里卖家，或确认子账号登录不会挤走主账号');
    console.log('\n=== 登录完成后，按此终端中的 Enter 继续 ===');

    // Wait for user to press Enter
    await new Promise(resolve => process.stdin.once('data', resolve));

    // After login, navigate to CRM
    await page.goto('https://crm.xiaoman.cn', { waitUntil: 'networkidle', timeout: 30000 });
    await page.waitForTimeout(3000);

    const newUrl = page.url();
    if (newUrl.includes('login')) {
      console.log('❌ 登录未成功，请重新运行脚本');
      await context.close();
      process.exit(1);
    }
    console.log('✅ 登录成功');
  } else {
    console.log('✅ OKKI 已有有效登录会话，无需重新登录（零风险）');
  }

  // Step 3: Extract data - go to inbox/message center
  console.log('\n=== 开始抓取数据 ===');

  // Navigate to the talk/im page to get customer conversations
  // OKKI CRM has a messaging section - try direct URL
  try {
    await page.goto('https://crm.xiaoman.cn/im', { waitUntil: 'networkidle', timeout: 15000 });
  } catch (e) {
    console.log('IM direct URL failed, trying navigation...');
  }
  await page.waitForTimeout(3000);

  // Check for chat/talk iframe
  const frames = page.frames();
  console.log(`页面frames: ${frames.length}个`);

  let chatFrame = frames.find(f =>
    f.url().includes('onetalk') || f.url().includes('talk') || f.url().includes('message')
  );

  // If no chat frame yet, try clicking into a conversation from the main page
  if (!chatFrame) {
    console.log('未找到聊天frame，尝试从主导航进入...');
    // Look for links/buttons to message center
    const navLinks = await page.evaluate(() => {
      return Array.from(document.querySelectorAll('a, button, div[class*="nav"], div[class*="menu"]'))
        .map(el => ({ text: (el.textContent || '').trim().substring(0, 60), href: el.href || '' }))
        .filter(x => x.text && (x.text.includes('消息') || x.text.includes('会话') || x.text.includes('客户') || x.text.includes('Inbox') || x.text.includes('chat')));
    });
    console.log('导航链接:', JSON.stringify(navLinks.slice(0, 15), null, 2));
  }

  // Step 4: Extract customer list from the page
  // Try to find and click on customer list elements
  console.log('\n=== 提取客户数据 ===');

  // Get all text content for analysis
  const pageText = await page.evaluate(() => document.body.innerText.substring(0, 10000));
  console.log('页面内容前500字:\n', pageText.substring(0, 500));

  // Check if there's an API response with customer data
  const customerApis = apiData.filter(d =>
    d.url.includes('customer') || d.url.includes('contact') ||
    d.url.includes('conversation') || d.url.includes('session') ||
    d.url.includes('chat') || d.url.includes('inbox') || d.url.includes('im/')
  );
  console.log(`\n拦截到 ${apiData.length} 个API响应，${customerApis.length} 个客户相关`);

  // Try clicking into the message/conversation section
  // OKKI navigation typically has sidebar items
  const clicked = await page.evaluate(() => {
    // Look for navigation that leads to messages/customers
    const allClickable = document.querySelectorAll('div[class*="menu-item"], li[class*="nav"], a[href*="im"], a[href*="customer"], a[href*="contact"], span[class*="nav"]');
    for (const el of allClickable) {
      const text = (el.textContent || '').trim();
      if (text && (text.includes('消息') || text.includes('会话') || text.includes('客户') || text.includes('Inbox'))) {
        try { el.click(); return `点击了: ${text}`; } catch(e) {}
      }
    }
    return '未找到可点击的导航';
  });
  console.log('导航点击结果:', clicked);
  await page.waitForTimeout(3000);

  // Step 5: Save ALL captured API data
  const ts = new Date().toISOString().replace(/[:.]/g, '-');
  const apiDumpPath = path.join(DATA_DIR, `api_dump_${ts}.json`);
  fs.writeFileSync(apiDumpPath, JSON.stringify(apiData, null, 2));
  console.log(`API数据已保存: ${apiDumpPath} (${apiData.length}个响应)`);

  // Step 6: Save full page DOM text
  const fullText = await page.evaluate(() => document.body.innerText);
  const textPath = path.join(DATA_DIR, `page_text_${ts}.txt`);
  fs.writeFileSync(textPath, fullText);
  console.log(`页面文本已保存: ${textPath} (${fullText.length}字符)`);

  // Step 7: Take screenshot
  const ssPath = path.join(DATA_DIR, `screenshot_${ts}.png`);
  await page.screenshot({ path: ssPath, fullPage: true });
  console.log(`截图已保存: ${ssPath}`);

  // Step 8: Check all frames for chat/conversation data
  for (const frame of page.frames()) {
    try {
      const fUrl = frame.url();
      if (fUrl.includes('onetalk') || fUrl.includes('talk') || fUrl.includes('alibaba.com')) {
        console.log(`\n=== 聊天Frame: ${fUrl.substring(0, 100)} ===`);
        const fText = await frame.evaluate(() => document.body.innerText.substring(0, 3000));
        console.log('Frame内容:', fText.substring(0, 500));
        const fPath = path.join(DATA_DIR, `frame_text_${ts}.txt`);
        fs.writeFileSync(fPath, fText);
      }
    } catch (e) {}
  }

  // Step 9: Try to extract structured customer data
  // Attempt to parse from API responses
  let customers = [];
  for (const resp of apiData) {
    try {
      const d = resp.data;
      if (d && d.data && d.data.list && Array.isArray(d.data.list)) {
        customers = d.data.list;
        console.log(`\n找到客户列表API: ${resp.url} (${customers.length}个客户)`);
        break;
      }
      if (d && d.list && Array.isArray(d.list)) {
        customers = d.list;
        console.log(`\n找到客户列表API: ${resp.url} (${customers.length}个客户)`);
        break;
      }
      if (d && Array.isArray(d) && d.length > 10 && d[0] && (d[0].name || d[0].companyName)) {
        customers = d;
        console.log(`\n找到客户数组API: ${resp.url} (${customers.length}个客户)`);
        break;
      }
    } catch (e) {}
  }

  // Save structured customer data
  const customerPath = path.join(DATA_DIR, `customers_${ts}.json`);
  fs.writeFileSync(customerPath, JSON.stringify({
    capturedAt: new Date().toISOString(),
    source: 'api_intercept',
    totalCustomers: customers.length,
    customers: customers,
    allApiResponses: apiData.map(d => ({ url: d.url, status: d.status, size: d.bodySize }))
  }, null, 2));
  console.log(`\n客户数据已保存: ${customerPath}`);

  console.log('\n=== 抓取完成 ===');
  console.log(`数据目录: ${DATA_DIR}`);
  console.log(`时间戳: ${ts}`);

  // Keep browser open for 5 seconds then close
  await page.waitForTimeout(5000);
  await context.close();
  console.log('浏览器已关闭');

})().catch(err => {
  console.error('脚本错误:', err);
  process.exit(1);
});

